import React, { useEffect, useState } from "react";
import axios from "axios";

const CustomerDashboard = () => {
  const [workers, setWorkers] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/auth/workers")
      .then(res => setWorkers(res.data));
  }, []);

  return (
    <div style={styles.container}>

      <h2>Find Workers</h2>

      {workers.map(w => (
        <div key={w._id} style={styles.card}>
          <h3>{w.name}</h3>
          <p>{w.skills?.join(", ")}</p>
          <p>₹{w.price}</p>

          <button style={styles.btn}>Book</button>
        </div>
      ))}

    </div>
  );
};

export default CustomerDashboard;

const styles = {
  container: { background: "#0b1220", minHeight: "100vh", color: "white", padding: "20px" },

  card: { background: "#111a2e", padding: "15px", margin: "10px 0" },

  btn: { background: "#22c55e", border: "none", padding: "8px", color: "white" }
};
